record.field:
for rec in records:
    total_line_count = len(rec.x_line_ids)
    included_line_count = len(rec.x_line_ids.filtered(lambda line: line.x_is_included))
    completion_ratio = (float(included_line_count) / float(total_line_count) * 100.0) if total_line_count else 0.0
    vals = {
        'x_total_line_count': total_line_count,
        'x_included_line_count': included_line_count,
        'x_completion_ratio': completion_ratio,
        'x_last_refresh_at': datetime.datetime.now(),
    }
    if rec.x_state not in ('signed', 'archived'):
        if total_line_count and included_line_count == total_line_count:
            vals['x_state'] = 'completed'
        elif included_line_count:
            vals['x_state'] = 'in_review'
        else:
            vals['x_state'] = 'draft'
    rec.write(vals)
    rec.message_post(body='Role composition progress refreshed.')

for rec in records:
    total_line_count = len(rec.x_line_ids)
    answered_lines = rec.x_line_ids.filtered(lambda line: line.x_is_answered or line.x_answer_text)
    total_score = sum((line.x_score or 0) for line in rec.x_line_ids)
    max_total_score = sum((line.x_max_score or 0) for line in rec.x_line_ids)
    completion_ratio = (float(len(answered_lines)) / float(total_line_count) * 100.0) if total_line_count else 0.0
    vals = {
        'x_total_score': total_score,
        'x_max_total_score': max_total_score,
        'x_completion_ratio': completion_ratio,
        'x_last_refresh_at': datetime.datetime.now(),
    }
    if rec.x_state not in ('signed', 'archived'):
        if total_line_count and len(answered_lines) == total_line_count:
            vals['x_state'] = 'completed'
        elif answered_lines:
            vals['x_state'] = 'in_review'
        else:
            vals['x_state'] = 'draft'
    rec.write(vals)
    rec.message_post(body='Interview evaluation progress refreshed.')

for rec in records:
    for line in rec.x_line_ids:
        latest_submission = line.x_submission_ids.sorted(key=lambda submission: (submission.x_received_at or submission.x_uploaded_at or submission.create_date or datetime.datetime.min, submission.id))[-1] if line.x_submission_ids else False
        line_vals = {
            'x_submission_count': len(line.x_submission_ids),
        }
        if latest_submission:
            line_vals['x_latest_submission_id'] = latest_submission.id
            received = bool(latest_submission.x_attachment_id or latest_submission.x_is_received)
            line_vals['x_is_completed'] = received
            if received:
                line_vals['x_completed_at'] = latest_submission.x_received_at or latest_submission.x_uploaded_at or datetime.datetime.now()
                line_vals['x_completed_by_id'] = latest_submission.x_uploaded_by_id.id if latest_submission.x_uploaded_by_id else env.user.id
            elif line.x_state not in ('signed', 'archived'):
                line_vals['x_is_completed'] = False
        elif line.x_state not in ('signed', 'archived'):
            line_vals['x_is_completed'] = False
        line.write(line_vals)
    required_lines = rec.x_line_ids.filtered(lambda line: line.x_is_required)
    completed_lines = rec.x_line_ids.filtered(lambda line: line.x_is_completed)
    required_line_count = len(required_lines)
    completed_line_count = len(completed_lines)
    missing_line_count = max(required_line_count - completed_line_count, 0)
    completion_ratio = (float(completed_line_count) / float(required_line_count) * 100.0) if required_line_count else 0.0
    vals = {
        'x_required_line_count': required_line_count,
        'x_completed_line_count': completed_line_count,
        'x_missing_line_count': missing_line_count,
        'x_completion_ratio': completion_ratio,
        'x_is_complete': bool(required_line_count and missing_line_count == 0),
        'x_last_refresh_at': datetime.datetime.now(),
    }
    if rec.x_state not in ('signed', 'archived'):
        if required_line_count and missing_line_count == 0:
            vals['x_state'] = 'completed'
        elif completed_line_count:
            vals['x_state'] = 'in_progress'
        else:
            vals['x_state'] = 'draft'
    rec.write(vals)
    rec.message_post(body='Document checklist progress refreshed.')

for rec in records:
    vals = {}
    if not rec.x_received_at and rec.x_attachment_id:
        vals['x_received_at'] = datetime.datetime.now()
    if rec.x_attachment_id:
        vals['x_is_received'] = True
    elif rec.x_state in ('submitted', 'reviewed', 'approved'):
        vals['x_is_received'] = True
    if not rec.x_uploaded_by_id:
        vals['x_uploaded_by_id'] = env.user.id
    if vals:
        rec.write(vals)
    if rec.x_checklist_line_id:
        line = rec.x_checklist_line_id
        line.write({
            'x_latest_submission_id': rec.id,
            'x_submission_count': len(line.x_submission_ids),
            'x_is_completed': bool(rec.x_attachment_id or rec.x_is_received),
            'x_completed_at': rec.x_received_at or datetime.datetime.now(),
            'x_completed_by_id': rec.x_uploaded_by_id.id if rec.x_uploaded_by_id else env.user.id,
        })
        if line.x_checklist_id:
            checklist = line.x_checklist_id
            required_lines = checklist.x_line_ids.filtered(lambda checklist_line: checklist_line.x_is_required)
            completed_lines = checklist.x_line_ids.filtered(lambda checklist_line: checklist_line.x_is_completed)
            required_line_count = len(required_lines)
            completed_line_count = len(completed_lines)
            missing_line_count = max(required_line_count - completed_line_count, 0)
            completion_ratio = (float(completed_line_count) / float(required_line_count) * 100.0) if required_line_count else 0.0
            checklist_vals = {
                'x_required_line_count': required_line_count,
                'x_completed_line_count': completed_line_count,
                'x_missing_line_count': missing_line_count,
                'x_completion_ratio': completion_ratio,
                'x_is_complete': bool(required_line_count and missing_line_count == 0),
                'x_last_refresh_at': datetime.datetime.now(),
            }
            if checklist.x_state not in ('signed', 'archived'):
                if required_line_count and missing_line_count == 0:
                    checklist_vals['x_state'] = 'completed'
                elif completed_line_count:
                    checklist_vals['x_state'] = 'in_progress'
                else:
                    checklist_vals['x_state'] = 'draft'
            checklist.write(checklist_vals)
            checklist.message_post(body='Document checklist progress refreshed from a submission.')
    rec.message_post(body='Document submission synchronized with the checklist.')

for rec in records:
    required_line_count = len(rec.x_line_ids)
    signed_line_count = len(rec.x_line_ids.filtered(lambda line: line.x_is_signed))
    pending_line_count = max(required_line_count - signed_line_count, 0)
    completion_ratio = (float(signed_line_count) / float(required_line_count) * 100.0) if required_line_count else 0.0
    vals = {
        'x_required_line_count': required_line_count,
        'x_signed_line_count': signed_line_count,
        'x_pending_line_count': pending_line_count,
        'x_completion_ratio': completion_ratio,
        'x_is_complete': bool(required_line_count and pending_line_count == 0),
        'x_last_refresh_at': datetime.datetime.now(),
    }
    if rec.x_state not in ('signed', 'archived'):
        if required_line_count and pending_line_count == 0:
            vals['x_state'] = 'completed'
        elif signed_line_count:
            vals['x_state'] = 'in_review'
        else:
            vals['x_state'] = 'draft'
    rec.write(vals)
    rec.message_post(body='Declaration envelope progress refreshed.')
